#include "sh1106_oled.h"
#include <Wire.h>
#include <Adafruit_GFX.h>
static Adafruit_SH1106G display(128,64,&Wire,-1);
void sh1106_setup(){Wire.begin();if(!display.begin(0x3C,true)){Serial.println("[sh1106] Fail!");return;}display.clearDisplay();display.setTextColor(SH110X_WHITE);display.display();Serial.println("[sh1106] OK 128x64");}
void sh1106_clear(){display.clearDisplay();}
void sh1106_text(int x,int y,const char*t,int s){display.setTextSize(s);display.setCursor(x,y);display.print(t);}
void sh1106_update(){display.display();}
